#include <stdio.h>
#include <math.h>
int main() {
    int n;
    scanf("%d", &n);
    int x[n], y[n];
    for (int i = 0; i < n; i++) {
        scanf("%d %d", &x[i], &y[i]);
    }
    int current_x = x[0], current_y = y[0];
    int total_distance = 0;
    for (int i = 1; i < n; i++) {
        int dx = x[i] - current_x;
        int dy = y[i] - current_y;
        total_distance += sqrt(dx * dx + dy * dy);
        current_x = x[i];
        current_y = y[i];
    }
    int dx = x[0] - current_x;
    int dy = y[0] - current_y;
    total_distance += sqrt(dx * dx + dy * dy);
    printf("%.0f\n", total_distance);
    return 0;
}

