import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[] x = new int[n];
        int[] y = new int[n];
        for (int i = 0; i < n; i++) {
            x[i] = scanner.nextInt();
            y[i] = scanner.nextInt();
        }
        int current_x = x[0], current_y = y[0];
        double total_distance = 0;
        for (int i = 1; i < n; i++) {
            int dx = x[i] - current_x;
            int dy = y[i] - current_y;
            total_distance += Math.sqrt(dx * dx + dy * dy);
            current_x = x[i];
            current_y = y[i];
        }
        int dx = x[0] - current_x;
        int dy = y[0] - current_y;
        total_distance += Math.sqrt(dx * dx + dy * dy);
        System.out.println(total_distance);
    }
}

