const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let n;
let x = [];
let y = [];
readline.on('line', line => {
    if (i === 0) {
        n = parseInt(line);
    } else {
        let input = line.split(' ');
        x.push(parseInt(input[0]));
        y.push(parseInt(input[1]));
    }
    i++;
    if (i > n) {
        let current_x = x[0], current_y = y[0];
        let total_distance = 0;
        for (let j = 1; j < n; j++) {
            let dx = x[j] - current_x;
            let dy = y[j] - current_y;
            total_distance += Math.sqrt(dx * dx + dy * dy);
            current_x = x[j];
            current_y = y[j];
        }
        let dx = x[0] - current_x;
        let dy = y[0] - current_y;
        total_distance += Math.sqrt(dx * dx + dy * dy);
        console.log(total_distance);
        readline.close();
    }
});

